// OR9 (standalone): opps created 2026 (open or won) + their contact emails -> fact_opportunity_contact.
// Isolated in its OWN workflow so it doesn't share memory with the big SF ingestion (which holds
// campaigns/opps/leads/~100k members) — that cumulative load is what OOM'd n8n. Here it's just
// rates + ~1,040 opps. Opportunity grain + nested OpportunityContactRoles subquery (a flat
// OpportunityContactRole query fans out org-wide, ~13k rows -> OOM). Amount -> EUR via CurrencyType.
const _rates = {};
for (const c of $('SF: Get Currency Rates').all().map((i) => i.json)) { _rates[c.IsoCode] = Number(c.ConversionRate); }
const _eur = _rates['EUR'] || 1;
function toEur(a, iso) { const x = Number(a) || 0; const r = _rates[iso]; return (r && isFinite(r)) ? x / r * _eur : x; }
const seen = {};
const out = [];
for (const o of $('SF: Get Opp Contacts').all().map((i) => i.json)) {
  const oppId = o.Id;
  if (!oppId) continue;
  const roles = (o.OpportunityContactRoles && o.OpportunityContactRoles.records) || [];
  const amt = toEur(o.Amount, o.CurrencyIsoCode);
  const created = String(o.CreatedDate || '').slice(0, 10) || null;
  for (const rc of roles) {
    const email = String((rc.Contact && rc.Contact.Email) || '').trim().toLowerCase();
    if (!email) continue;
    const key = oppId + '|' + email;
    if (seen[key]) continue;
    seen[key] = true;
    out.push({ json: {
      opp_id: String(oppId), contact_email: email, created_date: created,
      is_won: !!o.IsWon, is_closed: !!o.IsClosed, stage_name: o.StageName || null, amount_eur: amt,
    }});
  }
}
return out;
